const output = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const errors = [];

// Check if SSH failed
if (!output && stderr) {
  errors.push('SSH connection failed: ' + stderr.substring(0, 200));
  return [{ json: { status: 'ALERT', errors, dbAge: 999, dbSize: 0, raw: stderr.substring(0, 2000) } }];
}

// Check DB backup age
const ageMatch = output.match(/Age: (\d+) hours/);
const dbAge = ageMatch ? parseInt(ageMatch[1]) : 999;
if (dbAge > 26) errors.push(`DB backup tiene ${dbAge}h (max 26h)`);

// Check DB backup size
const sizeMatch = output.match(/Size: (\d+) bytes/);
const dbSize = sizeMatch ? parseInt(sizeMatch[1]) : 0;
if (dbSize < 1024) errors.push(`DB backup muy pequeno: ${dbSize} bytes`);

// Check if no backup found
if (output.includes('NO DB BACKUP FOUND')) errors.push('No hay backup de DB');
if (output.includes('NO WF BACKUP FOUND')) errors.push('No hay backup de workflows');

const status = errors.length > 0 ? 'ALERT' : 'OK';

return [{ json: { status, errors, dbAge, dbSize, raw: output.substring(0, 2000) } }];
